import { test, expect } from '@playwright/test';
import { createBookingData } from '../test-utils/factories';

test.describe('Booking API (getAvailableSlots)', () => {
  test('[P1] should return available slots for a valid ISO date', async ({ request }) => {
    // Setup test data
    const testDate = new Date();
    testDate.setDate(testDate.getDate() + 1); // Tomorrow
    testDate.setHours(12, 0, 0, 0);
    const isoDate = testDate.toISOString();

    const response = await request.post('/api/actions/getAvailableSlots', {
      data: [isoDate] // Server Action format (Array of arguments)
    });

    expect(response.status()).toBe(200);
    const result = await response.json();

    // Verify ActionState format
    expect(result).toHaveProperty('success');
    if (result.success) {
      expect(Array.isArray(result.data)).toBe(true);
      // Ensure slots follow format 'HH:00 - HH:00'
      if (result.data.length > 0) {
        expect(result.data[0]).toMatch(/^\d{2}:00 - \d{2}:00$/);
      }
    } else {
      expect(result.error).toBeDefined();
    }
  });

  test('[P1] should fail validation for invalid date format', async ({ request }) => {
    const response = await request.post('/api/actions/getAvailableSlots', {
      data: ['invalid-date-string']
    });

    expect(response.status()).toBe(200);
    const result = await response.json();

    expect(result.success).toBe(false);
    expect(result.message).toBe('Error de validación');
    expect(result.error).toHaveProperty('dateIso');
  });
});
